// État par défaut
const defaultRssi = { '101': -100, '107': -100, 'B012': -100 };
const defaultState = {
    '101':  { room: '101',  present: false, rssi: null, status: 'En attente', device: 'Aucun appareil' },
    '107':  { room: '107',  present: false, rssi: null, status: 'En attente', device: 'Aucun appareil' },
    'B012': { room: 'B012', present: false, rssi: null, status: 'En attente', device: 'Aucun appareil' }
};

let rssiMap = flow.get('rssiMap') || JSON.parse(JSON.stringify(defaultRssi));
let state   = flow.get('roomState') || JSON.parse(JSON.stringify(defaultState));

// ── Reset ou Init ─────────────────────────────────────────────
if (msg.topic === 'reset' || msg.topic === 'init') {
    rssiMap = JSON.parse(JSON.stringify(defaultRssi));
    state   = JSON.parse(JSON.stringify(defaultState));
    flow.set('rssiMap', rssiMap);
    flow.set('roomState', state);

} else {
    // ── Extraire la salle depuis le topic ─────────────────────
    // Topic : isisChallenge/borne/101  ou  /107  ou  /B012
    const parts = msg.topic.split('/');
    const room  = parts[parts.length - 1].toUpperCase();
    const rssi  = parseInt(msg.payload);

    if (isNaN(rssi)) {
        node.warn('Payload non numérique : ' + msg.payload);
        return null;
    }

    // Mettre à jour le RSSI de cette borne
    rssiMap[room] = rssi;
    flow.set('rssiMap', rssiMap);

    // ── Comparer les RSSI pour décider la salle ───────────────
    let bestRoom = null;
    let bestRssi = -100;

    Object.keys(rssiMap).forEach(r => {
        if (rssiMap[r] > -100 && rssiMap[r] > bestRssi) {
            bestRssi = rssiMap[r];
            bestRoom = r;
        }
    });

    // Remettre toutes les salles à Non détecté
    Object.keys(state).forEach(r => {
        state[r] = {
            room: r,
            present: false,
            rssi: rssiMap[r] > -100 ? rssiMap[r] : null,
            status: 'Non détecté',
            device: 'Aucun appareil'
        };
    });

    // Marquer uniquement la meilleure salle comme détectée
    if (bestRoom) {
        state[bestRoom] = {
            room: bestRoom,
            present: true,
            rssi: bestRssi,
            status: 'Validé ✅',
            device: 'ISIS Beacon'
        };
    }

    flow.set('roomState', state);
}

msg.payload = {
    title: 'Relais en duo',
    rooms: [state['101'], state['107'], state['B012']],
    rssiMap: rssiMap,
    legend: {
        ok:   'Badge détecté = passage validé',
        wait: 'Aucun badge = en attente',
        rssi: 'Plus le RSSI est proche de 0, plus le signal est fort'
    }
};

return msg;

